export function getCitiesByCounty(): Record<string, CityData[]> {
  const grouped: Record<string, CityData[]> = {};
  for (const city of SERVICE_AREAS) {
    if (!grouped[city.county]) grouped[city.county] = [];
    grouped[city.county].push(city);
  }
  return grouped;
}

export function getCityBySlug(slug: string): CityData | undefined {
  return SERVICE_AREAS.find((c) => c.slug === slug);
}

export function getNeighboringCities(slugs: string[]): CityData[] {
  return slugs
    .map((slug) => SERVICE_AREAS.find((c) => c.slug === slug))
    .filter(Boolean) as CityData[];
}
